<script setup lang="ts">
import { computed, onMounted, onUnmounted, ref } from "vue";
import { storeToRefs } from "pinia";
import { useRoute, useRouter } from "vue-router";
import { Activity, Archive, Bot, Check, ChevronRight, CircleCheck, CircleGauge, CircleX, Clock3, Cpu, Database, FileText, Filter, FolderOpen, Gauge, HardDrive, LayoutDashboard, MemoryStick, Network, Pause, Pin, Play, Plus, RefreshCw, Search, Settings, ShieldCheck, Sparkles, Terminal, Trash2, TriangleAlert, Wrench, X, Zap, ZoomIn } from "@lucide/vue";
import { invoke } from "@tauri-apps/api/core";
import { revealItemInDir } from "@tauri-apps/plugin-opener";
import type { AppSettings, CapabilityReport, CollectionCategory, CollectionStatus, Dashboard, DiagnosticCapability, DiagnosticEvent, DiagnosticMetricPoint, Incident, IncidentDetail, IncidentDraft, PatternAnalysis, RecoveryCandidate, ServiceStatus, Symptom } from "./types";
import { useAppStore } from "./stores/app";
import ConfirmDialog from "./components/ConfirmDialog.vue";
import DesktopSelect from "./components/DesktopSelect.vue";
import "./styles.css";

type Page = "dashboard"|"incidents"|"patterns"|"capabilities"|"privacy"|"settings";
type DiagnosticMetric = "cpu"|"memory"|"commit"|"diskLatency"|"diskQueue"|"diskThroughput"|"dpcIsr"|"network";
const route = useRoute(), router = useRouter();
const page = computed<Page>({get:()=>{const value=route.params.section;return typeof value==="string"&&["dashboard","incidents","patterns","capabilities","privacy","settings"].includes(value)?value as Page:"dashboard"},set:value=>{void router.push(`/${value}`);if(value==="capabilities"&&!capabilityReport.value)void loadCapabilities();if(value==="patterns")void loadPatterns()}});
const modal = ref(false), pendingTriggerTime = ref<string|null>(null), busy = ref(false), query = ref(""), tab = ref("summary"), errorMessage = ref(""), saved = ref(false);
const confirmation = ref<{type:"incident"|"all";id?:string}|null>(null), confirmationBusy = ref(false);
const monitoringBusy = ref(false);
const appStore = useAppStore();
const { dashboard, incidents, settings } = storeToRefs(appStore);
const selected = ref<IncidentDetail|null>(null);
const clockMs = ref(Date.now());
const collectionCategoryId = ref("incident"), showAllFiles = ref(false);
const recovery = ref<RecoveryCandidate|null>(null);
const capabilityReport = ref<CapabilityReport|null>(null), capabilityLoading = ref(false);
const patternAnalysis = ref<PatternAnalysis|null>(null), patternLoading = ref(false), patternSymptom = ref("all");
const serviceStatus = ref<ServiceStatus|null>(null), serviceBusy = ref(false);
const timelineZoom = ref<720 | 300 | 120>(720), analysisCursorOffset = ref<number|null>(null), selectedEventId = ref<string|null>(null), eventLevelFilter = ref<"all"|"important"|"warning">("all"), nearbyEventsOnly = ref(false), diagnosticEvidenceTab = ref<"processes"|"events"|"clues">("processes");
const draft = ref<IncidentDraft>({symptom:"system_freeze",severity:"high",duration_seconds:10,still_happening:false,description:""});
const nav = [{id:"dashboard",label:"概览",icon:LayoutDashboard},{id:"incidents",label:"事故记录",icon:Archive},{id:"patterns",label:"事故模式",icon:Activity},{id:"capabilities",label:"诊断能力",icon:Wrench},{id:"privacy",label:"隐私与数据",icon:ShieldCheck},{id:"settings",label:"设置",icon:Settings}] as const;
const capabilityCategories=["运行环境","基础采集","高级诊断","本地分析"];
const fullTimelineLabel=computed(()=>selected.value?`−${Math.round(selected.value.incident.pre_window_seconds/60)}m / +${Math.round(selected.value.incident.post_window_seconds/60)}m`:"完整范围");
const symptoms:{value:Symptom,label:string,icon:typeof Activity}[]=[{value:"system_slow",label:"系统卡顿",icon:Gauge},{value:"system_freeze",label:"系统无响应",icon:Pause},{value:"app_hang",label:"程序无响应",icon:Activity},{value:"network_slow",label:"网速慢",icon:Network},{value:"network_offline",label:"网络断开",icon:Zap},{value:"display_issue",label:"显示异常",icon:TriangleAlert},{value:"auto_restart",label:"自动重启",icon:RefreshCw},{value:"blue_screen",label:"蓝屏",icon:TriangleAlert},{value:"other",label:"其他",icon:FileText}];
const filtered=computed(()=>incidents.value.filter(x=>(x.symptom_label+(x.likely_cause||"")).includes(query.value)));
const activeCollection=computed(()=>selected.value?.collection.categories.find(item=>item.id===collectionCategoryId.value)||selected.value?.collection.categories[0]||null);
const activeCollectionFiles=computed(()=>activeCollection.value&&selected.value?selected.value.raw_files.filter(file=>activeCollection.value?.source_files.includes(file.name)):[]);
const diagnosticCharts:{id:DiagnosticMetric,label:string,color:string,unit:string}[]=[{id:"cpu",label:"CPU 使用率",color:"#ef6b42",unit:"%"},{id:"memory",label:"内存使用率",color:"#8d7ee8",unit:"%"},{id:"commit",label:"内存提交率",color:"#c978c4",unit:"%"},{id:"diskLatency",label:"磁盘延迟",color:"#e6a14b",unit:"ms"},{id:"diskQueue",label:"磁盘队列",color:"#d1844f",unit:""},{id:"diskThroughput",label:"磁盘吞吐",color:"#49a8c7",unit:"MB/s"},{id:"dpcIsr",label:"DPC / ISR 占用",color:"#e66d72",unit:"%"},{id:"network",label:"网络吞吐",color:"#4bc58d",unit:"KB/s"}];
const analysisRange=computed<[number,number]>(()=>{if(!selected.value)return[-600000,120000];if(timelineZoom.value===300)return[-240000,60000];if(timelineZoom.value===120)return[-90000,30000];return[-selected.value.incident.pre_window_seconds*1000,selected.value.incident.post_window_seconds*1000]});
const visibleAnalysisPoints=computed(()=>selected.value?.diagnostics.points.filter(point=>point.offset_ms>=analysisRange.value[0]&&point.offset_ms<=analysisRange.value[1])||[]);
const selectedAnalysisPoint=computed(()=>{const points=visibleAnalysisPoints.value;if(!points.length)return null;const target=analysisCursorOffset.value??0;return points.reduce((nearest,point)=>Math.abs(point.offset_ms-target)<Math.abs(nearest.offset_ms-target)?point:nearest)});
const selectedDiagnosticEvent=computed(()=>selected.value?.diagnostics.events.find(event=>event.id===selectedEventId.value)||null);
const filteredDiagnosticEvents=computed(()=>{const events=selected.value?.diagnostics.events||[];return events.filter(event=>(eventLevelFilter.value==="all"||eventLevelFilter.value==="important"&&event.level<=2||eventLevelFilter.value==="warning"&&event.level===3)&&(!nearbyEventsOnly.value||Math.abs(event.offset_ms-(selectedAnalysisPoint.value?.offset_ms||0))<=30000))});
const visiblePatterns=computed(()=>patternAnalysis.value?.patterns.filter(pattern=>patternSymptom.value==="all"||pattern.symptom===patternSymptom.value)||[]);
const fmt=(v:number)=>{
  if(v<1024)return `${Math.round(v)} B`;
  if(v<1048576)return `${(v/1024).toFixed(1)} KB`;
  if(v<1073741824)return `${(v/1048576).toFixed(v<10485760?2:1)} MB`;
  return `${(v/1073741824).toFixed(2)} GB`;
};
const date=(v:string)=>new Intl.DateTimeFormat("zh-CN",{month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"}).format(new Date(v));
const dateTime=(v:string)=>new Intl.DateTimeFormat("zh-CN",{month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit",second:"2-digit"}).format(new Date(v));
const status=(v:string)=>({capturing:"采集事故后窗口",freezing:"冻结证据",extracting:"提取事实",ready_for_analysis:"待分析",analyzing:"分析中",completed:"已完成",failed:"处理失败"} as Record<string,string>)[v]||v;
function captureCountdown(incident:Incident){if(incident.status!=="capturing")return null;const triggerMs=new Date(incident.trigger_time).getTime();if(!Number.isFinite(triggerMs))return null;const remaining=Math.ceil((triggerMs+incident.post_window_seconds*1000-clockMs.value)/1000);if(remaining<=0)return"即将完成";return`${Math.floor(remaining/60).toString().padStart(2,"0")}:${(remaining%60).toString().padStart(2,"0")}`}
const sourceLabel=(v:string)=>({manual:"主界面",shortcut:"全局快捷键",tray:"系统托盘",recovery:"异常重启恢复",automatic:"自动触发"} as Record<string,string>)[v]||v;
const call=<T,>(cmd:string,args?:Record<string,unknown>)=>invoke<T>(cmd,args);
function message(value:unknown){return typeof value==="string"?value:value instanceof Error?value.message:"操作失败"}
async function refresh(){try{[dashboard.value,incidents.value]=await Promise.all([call<Dashboard>("get_dashboard"),call<Incident[]>("list_incidents")]);if(selected.value)selected.value=await call("get_incident",{id:selected.value.incident.id})}catch(error){errorMessage.value=message(error)}}
async function loadCapabilities(){capabilityLoading.value=true;try{capabilityReport.value=await call<CapabilityReport>("get_diagnostic_capabilities")}catch(error){errorMessage.value=message(error)}finally{capabilityLoading.value=false}}
async function loadPatterns(){patternLoading.value=true;try{patternAnalysis.value=await call<PatternAnalysis>("get_pattern_analysis")}catch(error){errorMessage.value=message(error)}finally{patternLoading.value=false}}
async function loadServiceStatus(){try{serviceStatus.value=await call<ServiceStatus>("get_service_status")}catch(error){errorMessage.value=message(error)}}
async function changeService(install:boolean){serviceBusy.value=true;try{serviceStatus.value=await call<ServiceStatus>(install?"install_service":"uninstall_service");await refresh();if(capabilityReport.value)await loadCapabilities()}catch(error){errorMessage.value=message(error)}finally{serviceBusy.value=false}}
async function toggle(){if(monitoringBusy.value)return;monitoringBusy.value=true;try{dashboard.value=await call("set_monitoring",{enabled:!dashboard.value.monitoring})}catch(error){errorMessage.value=message(error)}finally{monitoringBusy.value=false}}
function openIncidentModal(){pendingTriggerTime.value=new Date().toISOString();modal.value=true}
async function create(){busy.value=true;try{selected.value=await call("create_incident",{draft:draft.value,triggerTime:pendingTriggerTime.value});modal.value=false;pendingTriggerTime.value=null;page.value="incidents";await refresh()}catch(error){errorMessage.value=message(error)}finally{busy.value=false}}
async function open(id:string){try{selected.value=await call("get_incident",{id});page.value="incidents";tab.value="summary";timelineZoom.value=720;analysisCursorOffset.value=null;selectedEventId.value=null;eventLevelFilter.value="all";nearbyEventsOnly.value=false;diagnosticEvidenceTab.value="processes";collectionCategoryId.value="incident";showAllFiles.value=false}catch(error){errorMessage.value=message(error)}}
async function analyze(){if(!selected.value)return;busy.value=true;try{selected.value=await call("analyze_incident",{id:selected.value.incident.id});await refresh()}catch(error){errorMessage.value=message(error)}finally{busy.value=false}}
async function togglePin(){if(!selected.value)return;try{selected.value=await call("set_incident_pinned",{id:selected.value.incident.id,pinned:!selected.value.pinned})}catch(error){errorMessage.value=message(error)}}
function remove(id:string){confirmation.value={type:"incident",id}}
function removeAll(){confirmation.value={type:"all"}}
async function confirmRemoval(){if(!confirmation.value)return;confirmationBusy.value=true;try{if(confirmation.value.type==="incident"){await call("delete_incident",{id:confirmation.value.id});selected.value=null}else{dashboard.value=await call("delete_all_data");selected.value=null}confirmation.value=null;await refresh()}catch(error){errorMessage.value=message(error)}finally{confirmationBusy.value=false}}
async function save(){try{settings.value=await call("save_settings",{settings:settings.value});saved.value=true;setTimeout(()=>saved.value=false,1800)}catch(error){errorMessage.value=message(error)}}
async function resolveRecovery(create:boolean){try{const detail=await call<IncidentDetail|null>("resolve_recovery",{create});recovery.value=null;if(detail){selected.value=detail;page.value="incidents"}}catch(error){errorMessage.value=message(error)}}
async function reveal(path:string){try{await revealItemInDir(path)}catch(error){errorMessage.value=message(error)}}
function diagnosticValue(point:DiagnosticMetricPoint,metric:DiagnosticMetric){if(metric==="cpu")return point.cpu_percent;if(metric==="memory")return point.memory_percent;if(metric==="commit")return point.commit_percent;if(metric==="diskLatency")return point.disk_latency_ms;if(metric==="diskQueue")return point.disk_queue_length;if(metric==="diskThroughput")return(point.disk_read_bytes_per_sec+point.disk_write_bytes_per_sec)/1048576;if(metric==="dpcIsr")return point.dpc_percent+point.interrupt_percent;return point.network_bytes_per_sec/1024}
function diagnosticMax(metric:DiagnosticMetric){const values=visibleAnalysisPoints.value.map(point=>diagnosticValue(point,metric));const peak=Math.max(...values,0);return ["cpu","memory","commit","dpcIsr"].includes(metric)?100:Math.max(peak*1.12,1)}
function diagnosticX(offsetMs:number){const[start,end]=analysisRange.value;return Math.max(0,Math.min(1000,(offsetMs-start)/(end-start)*1000))}
function diagnosticPolyline(metric:DiagnosticMetric){const max=diagnosticMax(metric);return visibleAnalysisPoints.value.map(point=>`${diagnosticX(point.offset_ms).toFixed(1)},${(102-diagnosticValue(point,metric)/max*88).toFixed(1)}`).join(" ")}
function diagnosticPeak(metric:DiagnosticMetric){return Math.max(...visibleAnalysisPoints.value.map(point=>diagnosticValue(point,metric)),0)}
function moveAnalysisCursor(event:MouseEvent){if(!visibleAnalysisPoints.value.length)return;const source=event.target;if(source instanceof Element&&source.closest(".diagnostic-charts>header,.diagnostic-charts>footer,.cursor-processes"))return;const target=event.currentTarget as Element;const svg=target instanceof SVGElement?target:target.querySelector(".diagnostic-chart svg");const rect=(svg||target).getBoundingClientRect();const ratio=Math.max(0,Math.min(1,(event.clientX-rect.left)/rect.width));const[start,end]=analysisRange.value;analysisCursorOffset.value=start+(end-start)*ratio}
function setAnalysisCursor(offsetMs:number){analysisCursorOffset.value=offsetMs}
function offsetLabel(offsetMs:number){const sign=offsetMs<0?"−":"+";const seconds=Math.round(Math.abs(offsetMs)/1000);return seconds>=60?`${sign}${Math.floor(seconds/60)}m ${seconds%60}s`:`${sign}${seconds}s`}
function diagnosticDisplay(point:DiagnosticMetricPoint|null,metric:DiagnosticMetric,unit:string){return point?`${diagnosticValue(point,metric).toFixed(metric==="diskLatency"?1:metric==="cpu"||metric==="memory"?1:2)} ${unit}`:"—"}
function processDuration(first:number,last:number){return Math.max(0,Math.round((last-first)/1000))}
function eventSeverity(event:DiagnosticEvent){return event.level<=2?"critical":event.level===3?"warning":"info"}
const capabilityStatus=(value:DiagnosticCapability["status"])=>({available:"可用",degraded:"运行异常",unavailable:"不可用",permission_required:"权限不足",not_installed:"未安装",misconfigured:"配置错误",disabled:"未启用"} as const)[value];
const capabilityIcon=(item:DiagnosticCapability)=>item.id==="ollama"?Bot:["elevation","service"].includes(item.id)?ShieldCheck:["pdh","dpc_counters","memory_api","ip_helper","wpr"].includes(item.id)?Activity:Terminal;
const collectionStatus=(value:CollectionStatus|"complete"|"partial")=>({available:"已采集",complete:"采集完整",pending:"采集中",partial:"部分可用",missing:"未生成",failed:"采集失败"} as const)[value];
const collectionIcon=(item:CollectionCategory)=>({incident:FileText,performance:Activity,process:Cpu,events:Archive,environment:Wrench,user_report:ShieldCheck,derived:Sparkles} as Record<string,typeof Activity>)[item.id]||Database;
let timer=0,countdownTimer=0;onMounted(async()=>{countdownTimer=setInterval(()=>clockMs.value=Date.now(),1000);try{[settings.value,recovery.value]=await Promise.all([call<AppSettings>("get_settings"),call<RecoveryCandidate|null>("get_recovery_candidate")]);await Promise.all([refresh(),loadServiceStatus()]);if(page.value==="capabilities")await loadCapabilities();if(page.value==="patterns")await loadPatterns();timer=setInterval(refresh,4000)}catch(error){errorMessage.value=message(error)}});onUnmounted(()=>{clearInterval(timer);clearInterval(countdownTimer)});
</script>

<template>
<div class="shell">
  <aside><div class="brand"><span><Activity/></span><div><b>系统黑盒子</b><small>系统故障记录器</small></div></div>
    <nav><button v-for="n in nav" :class="{active:page===n.id}" @click="page=n.id;selected=null"><component :is="n.icon"/>{{n.label}}</button></nav>
    <footer><p><i :class="{live:dashboard.monitoring}"></i>{{dashboard.monitoring?"监控正在运行":"监控已暂停"}}</p><small>数据仅保存在此设备</small></footer>
  </aside>
  <main><header><div><h1>{{selected?"事故详情":nav.find(n=>n.id===page)?.label}}</h1><p>{{selected?`${selected.incident.symptom_label} · ${date(selected.incident.created_at)}`:page==="capabilities"?"验证诊断组件、权限与本地分析服务":"持续记录系统状态，在故障消失前留下证据"}}</p></div><button class="icon" :disabled="capabilityLoading" @click="page==='capabilities'?loadCapabilities():refresh()"><RefreshCw :class="{spinning:capabilityLoading}"/></button></header>

    <section v-if="page==='dashboard'" class="page">
      <div v-if="recovery" class="recovery"><TriangleAlert/><span><b>检测到上次系统可能异常重启</b><small>{{recovery.evidence_summary}}<template v-if="recovery.last_sample_at"> · {{date(recovery.last_sample_at)}}</template></small></span><button class="secondary" @click="resolveRecovery(false)">忽略</button><button class="primary" @click="resolveRecovery(true)">创建事故记录</button></div>
      <div class="hero"><div><label><i :class="{off:!dashboard.monitoring}"></i>{{dashboard.monitoring?"正在记录系统状态":"当前未记录系统状态"}}</label><h2>电脑刚才出现了问题？</h2><p>立即保存故障前 10 分钟与后续 2 分钟的系统证据。</p></div><button class="incident" @click="openIncidentModal"><span>刚才发生了问题</span></button></div>
      <div class="metrics"><article v-for="m in [{n:'CPU',v:dashboard.cpu_percent,u:'%',max:100,i:Cpu},{n:'内存',v:dashboard.memory_percent,u:'%',max:100,i:MemoryStick},{n:'磁盘延迟',v:dashboard.disk_latency_ms,u:' ms',max:500,i:HardDrive},{n:'网络',v:dashboard.network_kbps,u:' KB/s',max:10240,i:Network}]"><div><component :is="m.i"/><span>{{m.n}}</span><b>{{m.v.toFixed(0)}}{{m.u}}</b></div><div class="meter"><i :style="{width:`${Math.min(100,m.v/m.max*100)}%`}"></i></div><small>最近一次本地采样</small></article></div>
      <div class="columns"><article class="panel"><div class="panel-title"><div><h3>采集状态</h3><p>{{monitoringBusy?(dashboard.monitoring?"正在安全停止性能收集器":"正在启动性能收集器"):"低开销后台记录"}}</p></div><button :class="dashboard.monitoring?'secondary':'primary'" :disabled="monitoringBusy" :aria-busy="monitoringBusy" @click="toggle"><RefreshCw v-if="monitoringBusy" class="spinning"/><Pause v-else-if="dashboard.monitoring"/><Play v-else/>{{monitoringBusy?(dashboard.monitoring?"正在暂停":"正在启动"):dashboard.monitoring?"暂停":"开始监控"}}</button></div>
        <dl><div><dt><Clock3/>本次运行</dt><dd>{{Math.floor(dashboard.uptime_seconds/60)}} 分钟</dd></div><div><dt><Database/>循环数据</dt><dd>{{fmt(dashboard.storage_bytes)}} / {{settings.rolling_limit_gb}} GB</dd></div><div><dt><CircleGauge/>采样间隔</dt><dd>{{dashboard.effective_interval_seconds||settings.sample_interval_seconds}} 秒<span v-if="dashboard.effective_interval_seconds>settings.sample_interval_seconds">（开销保护已降级）</span></dd></div><div><dt><Activity/>性能循环日志</dt><dd>{{dashboard.etw_status}}</dd></div><div><dt><Activity/>WPR 高精度环形</dt><dd>{{dashboard.wpr_status}}</dd></div><div><dt><Zap/>全局快捷键</dt><dd>{{dashboard.shortcut_status}}</dd></div><div><dt><Cpu/>自身开销</dt><dd>CPU {{dashboard.blackbox_cpu_percent.toFixed(1)}}% · 内存 {{fmt(dashboard.blackbox_memory_bytes)}} · 写入 {{dashboard.blackbox_disk_write_kbps.toFixed(1)}} KB/s</dd></div></dl></article>
        <article class="panel recent"><div class="panel-title"><div><h3>最近事故</h3><p>共 {{incidents.length}} 条本地记录</p></div><button class="link" @click="page='incidents'">查看全部 <ChevronRight/></button></div>
          <p v-if="!incidents.length" class="empty"><Archive/>事故记录会显示在这里</p><button v-for="x in incidents.slice(0,3)" @click="open(x.id)"><i :class="x.severity"></i><span><b>{{x.symptom_label}}</b><small>{{date(x.created_at)}} · {{status(x.status)}}<template v-if="captureCountdown(x)"> · 剩余 {{captureCountdown(x)}}</template></small></span><em>{{x.likely_cause||"等待分析"}}</em><ChevronRight/></button></article></div>
    </section>

    <section v-else-if="page==='incidents'&&!selected" class="page"><div class="toolbar"><label><Search/><input v-model="query" placeholder="搜索事故或原因"></label><button class="primary" @click="openIncidentModal"><Plus/>标记事故</button></div>
      <div class="table"><div class="thead"><span>时间与症状</span><span>状态</span><span>最可能原因</span><span>可信度</span></div><button v-for="x in filtered" @click="open(x.id)"><span><i :class="x.severity"></i><b>{{x.symptom_label}}</b><small>{{date(x.created_at)}}</small></span><span class="incident-status"><em>{{status(x.status)}}</em><small v-if="captureCountdown(x)"><Clock3/>剩余 {{captureCountdown(x)}}</small></span><span>{{x.likely_cause||"等待结构化分析"}}</span><span>{{x.confidence?Math.round(x.confidence*100)+"%":"—"}}</span></button><p v-if="!filtered.length" class="empty"><Archive/>没有事故记录</p></div>
    </section>

    <section v-else-if="page==='patterns'" class="page patterns-page">
      <div v-if="patternAnalysis" class="pattern-overview"><article class="panel"><small>事故总数</small><b>{{patternAnalysis.incident_count}}</b></article><article class="panel"><small>已有结构化证据</small><b>{{patternAnalysis.analyzed_incident_count}}</b></article><article class="panel"><small>重复模式</small><b>{{patternAnalysis.patterns.length}}</b></article></div>
      <div class="pattern-toolbar"><div><h2>多事故模式分析</h2><p>比较同类事故中重复出现的性能异常和 Windows 事件。</p></div><DesktopSelect v-model="patternSymptom" aria-label="事故症状筛选" :options="[{value:'all',label:'全部症状'},...(patternAnalysis?.symptoms||[]).map(item=>({value:item.symptom,label:`${item.label}（${item.count}）`}))]"/><button class="secondary" :disabled="patternLoading" @click="loadPatterns"><RefreshCw :class="{spinning:patternLoading}"/>重新统计</button></div>
      <div v-if="patternLoading&&!patternAnalysis" class="panel capability-loading"><RefreshCw class="spinning"/><span><b>正在比较事故证据</b><small>只分析本机已有事故包。</small></span></div>
      <div v-else class="pattern-list"><article v-for="pattern in visiblePatterns" class="panel"><header><i :class="pattern.severity"></i><div><b>{{pattern.title}}</b><small>{{pattern.symptom_label}} · {{pattern.category}}</small></div><strong>{{Math.round(pattern.occurrence_ratio*100)}}%</strong></header><p>已有结构化证据的 {{pattern.comparable_incidents}} 次同类事故中有 {{pattern.occurrence_count}} 次出现；平均位于标记时刻 {{offsetLabel(pattern.average_offset_ms)}}，范围 {{offsetLabel(pattern.earliest_offset_ms)}} 至 {{offsetLabel(pattern.latest_offset_ms)}}。<template v-if="pattern.near_trigger_count">其中 {{pattern.near_trigger_count}} 次发生在故障前 5 秒内。</template></p><footer><span>{{pattern.incident_ids.length}} 个关联事故</span><span>最近出现：{{date(pattern.last_seen_at)}}</span></footer></article><p v-if="!visiblePatterns.length" class="panel empty"><Activity/>至少需要两次同类事故出现相同异常，才能形成模式。</p></div>
    </section>

    <section v-else-if="selected" class="page"><div class="detail-head panel"><div><button class="back" @click="selected=null">← 返回事故列表</button><h2><TriangleAlert/>{{selected.incident.symptom_label}}</h2><p>{{selected.incident.id}} · {{date(selected.incident.trigger_time)}} · {{status(selected.incident.status)}}</p></div><div><button class="secondary" @click="togglePin"><Pin/>{{selected.pinned?"取消固定":"固定保留"}}</button><button class="danger" @click="remove(selected.incident.id)"><Trash2/>删除</button><button class="primary" :disabled="busy || !['ready_for_analysis','completed'].includes(selected.incident.status)" @click="analyze"><Sparkles/>{{selected.report?"重新分析":"开始分析"}}</button></div></div>
      <div v-if="['capturing','freezing','extracting'].includes(selected.incident.status)" class="processing"><RefreshCw/><span><b>{{status(selected.incident.status)}} <em v-if="captureCountdown(selected.incident)">剩余 {{captureCountdown(selected.incident)}}</em></b> 后台正在保存事故现场，窗口可以正常关闭或切换。</span></div>
      <div v-else-if="selected.incident.status==='failed'" class="processing failed"><TriangleAlert/><span><b>证据处理失败</b> 事故目录已保留，可在“采集内容”中检查 pipeline-error.txt。</span></div>
      <div class="tabs"><button v-for="t in [['summary','摘要'],['diagnostics','人工分析'],['evidence','证据'],['ai','AI 分析'],['collection','采集内容']]" :class="{active:tab===t[0]}" @click="tab=t[0]">{{t[1]}}</button></div>
      <div v-if="tab==='summary'" class="detail-grid"><article class="panel report"><label>诊断摘要</label><h2>{{selected.report?.summary||"证据已保存，等待本地分析"}}</h2><p v-if="!selected.report">规则引擎会先提取确定性事实，再由本地模型解释。</p><div v-for="(c,i) in selected.report?.likely_causes"><i>{{i+1}}</i><span><b>{{c.title}}</b><p>{{c.explanation}}</p></span><em>{{Math.round(c.confidence*100)}}%</em></div></article>
        <article class="panel facts"><h3>事故信息</h3><dl><div><dt>严重程度</dt><dd>{{selected.incident.severity}}</dd></div><div><dt>触发来源</dt><dd>{{sourceLabel(selected.incident.trigger_source)}}</dd></div><div><dt>故障前窗口</dt><dd>{{Math.round(selected.incident.pre_window_seconds/60)}} 分钟</dd></div><div><dt>故障后窗口</dt><dd>{{Math.round(selected.incident.post_window_seconds/60)}} 分钟</dd></div><div><dt>敏感等级</dt><dd>Level {{selected.collection.sensitivity_level}}</dd></div><div><dt>应用版本</dt><dd>{{selected.incident.app_version}}</dd></div></dl></article></div>
      <div v-else-if="tab==='diagnostics'" class="diagnostic-workspace">
        <section class="panel diagnostic-heading"><div><label>人工诊断工作台</label><h2>故障前后证据关联</h2><p>所有时间均以用户标记故障的时刻为 0；这里展示事实和线索，不自动宣称根因。</p></div><div class="timeline-tools"><span><ZoomIn/>范围</span><button v-for="option in [{value:720,label:fullTimelineLabel},{value:300,label:'−4m / +1m'},{value:120,label:'−90s / +30s'}]" :class="{active:timelineZoom===option.value}" @click="timelineZoom=option.value as 720|300|120">{{option.label}}</button></div></section>
        <section v-if="selected.diagnostics.highlights.length" class="diagnostic-highlights"><button v-for="highlight in selected.diagnostics.highlights" :class="highlight.severity" @click="setAnalysisCursor(highlight.offset_ms)"><span><b>{{highlight.label}}</b><em>{{offsetLabel(highlight.offset_ms)}}</em></span><strong>{{highlight.value}}</strong><small>{{highlight.description}}</small></button></section>
        <section class="panel diagnostic-charts" @mousemove="moveAnalysisCursor"><header><div><h3>同步性能曲线</h3><p>在任意曲线上移动鼠标，所有指标会锁定到同一个采样时刻。</p></div><span v-if="selectedAnalysisPoint"><Clock3/>{{offsetLabel(selectedAnalysisPoint.offset_ms)}} · {{dateTime(selectedAnalysisPoint.timestamp)}}</span></header>
          <div v-if="visibleAnalysisPoints.length" class="diagnostic-chart" v-for="chart in diagnosticCharts"><div><b>{{chart.label}}</b><strong>{{diagnosticDisplay(selectedAnalysisPoint,chart.id,chart.unit)}}</strong><small>峰值 {{diagnosticPeak(chart.id).toFixed(chart.id==='diskLatency'?1:2)}} {{chart.unit}}</small></div><svg viewBox="0 0 1000 110" preserveAspectRatio="none"><line v-for="y in [22,62,102]" x1="0" :y1="y" x2="1000" :y2="y" class="chart-grid"/><line :x1="diagnosticX(0)" y1="8" :x2="diagnosticX(0)" y2="105" class="chart-trigger"/><polyline :points="diagnosticPolyline(chart.id)" :style="{stroke:chart.color}"/><line v-if="selectedAnalysisPoint" :x1="diagnosticX(selectedAnalysisPoint.offset_ms)" y1="7" :x2="diagnosticX(selectedAnalysisPoint.offset_ms)" y2="105" class="chart-cursor"/><circle v-if="selectedAnalysisPoint" :cx="diagnosticX(selectedAnalysisPoint.offset_ms)" :cy="102-diagnosticValue(selectedAnalysisPoint,chart.id)/diagnosticMax(chart.id)*88" r="5" :style="{fill:chart.color}"/></svg></div>
          <p v-else class="empty"><Activity/>这个事故尚未生成性能样本</p>
          <footer v-if="selectedAnalysisPoint"><span><Cpu/>CPU <b>{{selectedAnalysisPoint.cpu_percent.toFixed(1)}}%</b></span><span><MemoryStick/>内存 <b>{{selectedAnalysisPoint.memory_percent.toFixed(1)}}%</b></span><span><HardDrive/>可用 <b>{{fmt(selectedAnalysisPoint.available_memory_bytes)}}</b></span><span><Database/>提交率 <b>{{selectedAnalysisPoint.commit_percent.toFixed(1)}}%</b></span><span><Activity/>DPC / ISR <b>{{selectedAnalysisPoint.dpc_percent.toFixed(1)}}% / {{selectedAnalysisPoint.interrupt_percent.toFixed(1)}}%</b></span><span><Network/>错误/丢弃 <b>{{selectedAnalysisPoint.network_errors}} / {{selectedAnalysisPoint.network_discards}}</b></span></footer>
          <div v-if="selectedAnalysisPoint?.top_processes.length" class="cursor-processes"><label>该采样点 Top 进程</label><span v-for="process in selectedAnalysisPoint.top_processes.slice(0,5)"><b>{{process.name}}</b><small>PID {{process.pid}} · 核心等效 {{process.cpu_core_percent.toFixed(1)}}%</small><em>整机 CPU {{process.cpu_percent.toFixed(1)}}% · 内存 {{fmt(process.memory_bytes)}} · I/O {{fmt(process.disk_read_bytes_per_sec+process.disk_write_bytes_per_sec)}}/s</em></span></div>
        </section>
        <section class="panel diagnostic-evidence"><header><div><h3>证据列表</h3><p>按类型查看事故窗口内的进程、Windows 事件和本地规则线索。</p></div><nav><button :class="{active:diagnosticEvidenceTab==='processes'}" @click="diagnosticEvidenceTab='processes'"><Cpu/>进程活动 <span>{{selected.diagnostics.processes.length}}</span></button><button :class="{active:diagnosticEvidenceTab==='events'}" @click="diagnosticEvidenceTab='events'"><Archive/>Windows 事件 <span>{{filteredDiagnosticEvents.length}}</span></button><button :class="{active:diagnosticEvidenceTab==='clues'}" @click="diagnosticEvidenceTab='clues'"><Sparkles/>诊断线索 <span>{{selected.observations.length}}</span></button></nav></header>
          <article v-if="diagnosticEvidenceTab==='processes'" class="diagnostic-processes"><div class="diagnostic-table-head"><span>进程</span><span>峰值时刻</span><span>CPU</span><span>核心等效</span><span>内存</span><span>磁盘 I/O</span></div><div class="process-list"><button v-for="process in selected.diagnostics.processes.slice(0,16)" @click="setAnalysisCursor(process.peak_offset_ms)"><span><b>{{process.name}}</b><small>PID {{process.pid}} · 出现 {{process.sample_count}} 次 · {{processDuration(process.first_offset_ms,process.last_offset_ms)}} 秒</small></span><em>{{offsetLabel(process.peak_offset_ms)}}</em><strong>{{process.max_cpu_percent.toFixed(1)}}%</strong><strong class="core-percent">{{process.max_cpu_core_percent.toFixed(0)}}%</strong><strong>{{fmt(process.max_memory_bytes)}}</strong><strong>{{fmt(process.max_disk_read_bytes_per_sec+process.max_disk_write_bytes_per_sec)}}/s</strong></button><p v-if="!selected.diagnostics.processes.length" class="empty">没有进程采样</p></div></article>
          <article v-else-if="diagnosticEvidenceTab==='events'" class="diagnostic-events"><div class="event-tools"><span><Filter/>筛选</span><button :class="{active:eventLevelFilter==='all'}" @click="eventLevelFilter='all'">全部</button><button :class="{active:eventLevelFilter==='important'}" @click="eventLevelFilter='important'">关键/错误</button><button :class="{active:eventLevelFilter==='warning'}" @click="eventLevelFilter='warning'">警告</button><button :class="{active:nearbyEventsOnly}" @click="nearbyEventsOnly=!nearbyEventsOnly">游标附近 ±30 秒</button></div><div class="event-list"><button v-for="event in filteredDiagnosticEvents" :class="{active:selectedEventId===event.id}" @click="selectedEventId=event.id;setAnalysisCursor(event.offset_ms)"><i :class="eventSeverity(event)"></i><span><b>{{event.provider||"未知 Provider"}}</b><small>{{event.channel}} · Event {{event.event_id??"—"}} · {{event.level_label}}</small><p>{{event.summary}}</p></span><em>{{offsetLabel(event.offset_ms)}}</em></button><p v-if="!filteredDiagnosticEvents.length" class="empty">当前筛选范围没有事件</p></div><section v-if="selectedDiagnosticEvent" class="event-inspector"><header><div><span :class="['event-level',eventSeverity(selectedDiagnosticEvent)]">{{selectedDiagnosticEvent.level_label}}</span><h3>{{selectedDiagnosticEvent.provider}} · Event {{selectedDiagnosticEvent.event_id??"—"}}</h3></div><button class="icon" @click="selectedEventId=null"><X/></button></header><dl><div><dt>相对时间</dt><dd>{{offsetLabel(selectedDiagnosticEvent.offset_ms)}}</dd></div><div><dt>日志通道</dt><dd>{{selectedDiagnosticEvent.channel}}</dd></div><div><dt>记录时间</dt><dd>{{selectedDiagnosticEvent.timestamp?dateTime(selectedDiagnosticEvent.timestamp):"未知"}}</dd></div><div><dt>计算机</dt><dd>{{selectedDiagnosticEvent.computer||"未记录"}}</dd></div></dl><pre>{{selectedDiagnosticEvent.details||selectedDiagnosticEvent.summary}}</pre></section></article>
          <article v-else class="diagnostic-clues"><button v-for="clue in selected.observations" @click="setAnalysisCursor(clue.offset_ms)"><i :class="clue.severity"></i><span><b>{{clue.title}}</b><p>{{clue.description}}</p><small>{{clue.source}}</small></span><em>{{offsetLabel(clue.offset_ms)}}</em></button><p v-if="!selected.observations.length" class="empty">尚未生成诊断线索</p></article>
        </section>
      </div>
      <div v-else-if="tab==='evidence'" class="panel evidence"><h3>结构化观察结果</h3><div v-for="o in selected.observations"><Activity/><span><b>{{o.title}}</b><p>{{o.description}}</p><code>{{o.id}} · {{o.source}} · {{o.offset_ms/1000}}s</code></span><em :class="o.severity">{{o.severity}}</em></div><p v-if="!selected.observations.length" class="empty">未提取到异常</p></div>
      <div v-else-if="tab==='ai'" class="panel ai"><Bot/><h3>本地 AI 诊断</h3><p>AI 只能解释已有证据，不能修改数据或执行修复。</p><h2>{{selected.report?.summary||"尚未生成报告"}}</h2></div>
      <div v-else class="collection-view">
        <section class="panel collection-overview"><div class="collection-overview-title"><span :class="['collection-health',selected.collection.status]"><RefreshCw v-if="selected.collection.status==='pending'" class="spinning"/><TriangleAlert v-else-if="['partial','failed'].includes(selected.collection.status)"/><CircleCheck v-else/></span><div><h3>{{collectionStatus(selected.collection.status)}}</h3><p>以下内容来自这个事故包的实际文件，不代表计划采集项。</p></div></div><div class="collection-stats"><span><small>计划窗口</small><b>{{selected.collection.planned_window}}</b></span><span><small>实际覆盖</small><b>{{selected.collection.actual_coverage}}</b></span><span><small>数据规模</small><b>{{selected.collection.sample_count}} 样本 · {{selected.collection.event_count}} 事件</b></span><span><small>本地占用</small><b>{{fmt(selected.collection.total_size_bytes)}}</b></span><span><small>最高敏感等级</small><b>Level {{selected.collection.sensitivity_level}}</b></span></div></section>
        <section class="collection-browser"><nav class="collection-nav" aria-label="采集内容分类"><header><b>内容分类</b><small>{{selected.collection.categories.length}} 类</small></header><button v-for="item in selected.collection.categories" :class="{active:activeCollection?.id===item.id}" @click="collectionCategoryId=item.id;showAllFiles=false"><span class="collection-nav-icon"><component :is="collectionIcon(item)"/></span><span><b>{{item.label}}</b><small>{{item.description}}</small><em>{{item.quantity}}</em></span><i :class="item.status"></i></button></nav>
          <article v-if="activeCollection" class="panel collection-detail"><header><span class="collection-detail-icon"><component :is="collectionIcon(activeCollection)"/></span><div><h2>{{activeCollection.label}}</h2><p>{{activeCollection.description}}</p></div><span :class="['collection-status',activeCollection.status]">{{collectionStatus(activeCollection.status)}}</span></header>
            <div class="collection-meta"><span><small>数量</small><b>{{activeCollection.quantity}}</b></span><span v-if="activeCollection.coverage"><small>覆盖范围</small><b>{{activeCollection.coverage}}</b></span><span><small>占用空间</small><b>{{fmt(activeCollection.size_bytes)}}</b></span><span><small>敏感等级</small><b>Level {{activeCollection.sensitivity_level}}</b></span></div>
            <section class="collection-fields"><h3>已记录信息</h3><dl><div v-for="field in activeCollection.details"><dt>{{field.label}}</dt><dd>{{field.value}}</dd></div></dl></section>
            <section class="collection-files"><h3>对应技术文件 <small>{{activeCollectionFiles.length}} 个</small></h3><div v-for="file in activeCollectionFiles"><FileText/><span><b>{{file.name}}</b><small>{{file.kind}}</small></span><em>{{fmt(file.size_bytes)}}</em></div><p v-if="!activeCollectionFiles.length">当前没有生成对应文件。</p></section>
            <footer><button class="secondary" @click="showAllFiles=!showAllFiles"><Database/>{{showAllFiles?"收起全部文件":`查看全部事故包文件（${selected.raw_files.length}）`}}</button><button class="secondary" @click="reveal(selected.data_path)"><FolderOpen/>在文件资源管理器中定位</button></footer>
            <section v-if="showAllFiles" class="collection-files all-files"><h3>全部事故包文件</h3><div v-for="file in selected.raw_files"><FileText/><span><b>{{file.name}}</b><small>{{file.kind}}</small></span><em>{{fmt(file.size_bytes)}}</em></div><code>{{selected.data_path}}</code></section>
          </article>
        </section>
      </div>
    </section>

    <section v-else-if="page==='capabilities'" class="page capabilities-page">
      <div v-if="capabilityReport" class="capability-overview panel"><div><span :class="['capability-health',{warning:capabilityReport.attention}]"><CircleCheck v-if="!capabilityReport.attention"/><TriangleAlert v-else/></span><div><h2>{{capabilityReport.attention?`${capabilityReport.attention} 项基础能力需要处理`:"基础诊断能力正常"}}</h2><p>{{capabilityReport.available}} 项能力可用 · 当前进程{{capabilityReport.is_elevated?"已提升权限":"未提升权限"}} · 检测于 {{date(capabilityReport.checked_at)}}</p></div></div><button class="secondary" :disabled="capabilityLoading" @click="loadCapabilities"><RefreshCw :class="{spinning:capabilityLoading}"/>重新检测</button></div>
      <div v-else class="panel capability-loading"><RefreshCw class="spinning"/><span><b>正在检测诊断能力</b><small>只检查本机组件、权限与已配置的本地服务。</small></span></div>
      <article v-for="category in capabilityCategories" v-if="capabilityReport" class="panel capability-group"><header><div><h3>{{category}}</h3><p>{{category==="基础采集"?"当前版本直接依赖的系统采集能力":category==="高级诊断"?"WPR 已用于事故 ETL，其他工具按需启用":category==="本地分析"?"只连接设置中明确配置的本机服务":"影响后台持续采集与受保护诊断功能"}}</p></div><span>{{capabilityReport.capabilities.filter(item=>item.category===category&&item.status==="available").length}} / {{capabilityReport.capabilities.filter(item=>item.category===category).length}} 可用</span></header>
        <div v-for="item in capabilityReport.capabilities.filter(item=>item.category===category)" class="capability-row"><span :class="['capability-icon',item.status]"><component :is="capabilityIcon(item)"/></span><div class="capability-main"><div><b>{{item.name}}</b><span v-if="item.required_now" class="required-tag">当前使用</span><span v-else class="optional-tag">可选</span></div><p>{{item.usage}}</p><small>{{item.detail}}</small><code v-if="item.path">{{item.path}}</code><aside v-if="item.recommendation"><TriangleAlert/>{{item.recommendation}}</aside></div><div class="capability-state"><span :class="item.status"><CircleCheck v-if="item.status==='available'"/><CircleX v-else-if="['unavailable','degraded','misconfigured'].includes(item.status)"/><TriangleAlert v-else/>{{capabilityStatus(item.status)}}</span><small v-if="item.requires_admin">需要管理员权限</small><small v-if="item.version">{{item.version}}</small></div></div>
      </article>
    </section>

    <section v-else-if="page==='privacy'" class="page"><div class="privacy panel"><ShieldCheck/><div><h2>默认零上传</h2><p>无需账号、无遥测。原始日志与事故包始终保存在此设备。</p></div></div><div class="columns"><article class="panel"><h3>当前收集的数据</h3><ul><li><Check/>CPU、内存、磁盘性能指标 <em>Level 0</em></li><li><Check/>进程名与 Event Provider <em>Level 1</em></li><li><Check/>Windows 事件与用户主动填写内容 <em>最高 Level 2</em></li><li><X/>键盘、屏幕、文件正文 <em>不收集</em></li></ul><p>当前事故包最高敏感等级：Level {{dashboard.sensitivity_level_max}}</p></article><article class="panel"><h3>本地存储</h3><p>{{incidents.length}} 条事故 · 事故包 {{fmt(dashboard.incident_storage_bytes)}} · 循环数据 {{fmt(dashboard.storage_bytes)}}</p><code class="data-path">{{dashboard.data_path}}</code><div class="storage-actions"><button class="secondary" @click="reveal(dashboard.data_path)"><FolderOpen/>定位数据目录</button><button class="danger" @click="removeAll"><Trash2/>删除所有本地数据</button></div></article></div></section>
    <section v-else class="page settings"><article class="panel service-settings"><h3>后台采集服务</h3><label><span><b>Windows Service</b><small>开机启动，关闭界面后仍继续记录；安装和卸载需要管理员权限。</small></span><span :class="['service-badge',{active:serviceStatus?.connected}]">{{serviceStatus?.connected?"已连接":serviceStatus?.running?"运行但 IPC 不可用":serviceStatus?.installed?"已安装但未运行":"未安装"}}</span></label><div class="service-actions"><button class="secondary" :disabled="serviceBusy" @click="loadServiceStatus"><RefreshCw :class="{spinning:serviceBusy}"/>刷新状态</button><button v-if="!serviceStatus?.installed" class="primary" :disabled="serviceBusy" @click="changeService(true)"><ShieldCheck/>安装并启动</button><button v-else class="danger" :disabled="serviceBusy" @click="changeService(false)"><Trash2/>停止并卸载</button></div></article><article class="panel"><h3>监控与存储</h3><label><span><b>采样间隔</b><small>较短间隔开销更高</small></span><DesktopSelect v-model="settings.sample_interval_seconds" aria-label="采样间隔" :options="[1,2,5,10].map(value=>({value,label:`${value} 秒`}))"/></label><label><span><b>事故保留期限</b><small>固定的事故不受期限和配额清理影响。</small></span><DesktopSelect v-model="settings.retention_days" aria-label="事故保留期限" :options="[{value:7,label:'7 天'},{value:30,label:'30 天'},{value:90,label:'90 天'},{value:0,label:'永久'}]"/></label><label><span><b>循环数据上限</b><small>达到限制后覆盖最旧的低成本性能记录。</small></span><DesktopSelect v-model="settings.rolling_limit_gb" aria-label="循环数据上限" :options="[1,2,4,8].map(value=>({value,label:`${value} GB`}))"/></label><label><span><b>事故数据总上限</b></span><DesktopSelect v-model="settings.incident_limit_gb" aria-label="事故数据总上限" :options="[10,20,50,100].map(value=>({value,label:`${value} GB`}))"/></label></article><article class="panel"><h3>自动事故触发</h3><label><span><b>自动触发</b><small>持续异常达到阈值后创建事故；包含冷却、合并和每小时上限。</small></span><DesktopSelect v-model="settings.auto_trigger_enabled" aria-label="自动触发" :options="[{value:false,label:'关闭'},{value:true,label:'启用'}]"/></label><label><span><b>同类事故冷却时间</b></span><DesktopSelect v-model="settings.auto_trigger_cooldown_minutes" aria-label="自动触发冷却时间" :options="[5,15,30,60].map(value=>({value,label:`${value} 分钟`}))"/></label><label><span><b>每小时自动事故上限</b></span><DesktopSelect v-model="settings.auto_trigger_max_per_hour" aria-label="每小时自动事故上限" :options="[1,2,4,8].map(value=>({value,label:`${value} 次`}))"/></label><div class="auto-trigger-rules"><small>内置持续触发条件</small><span>CPU 饱和</span><span>Commit 压力</span><span>磁盘高延迟</span><span>DPC / ISR</span><span>网络错误与丢弃</span><span>GPU reset</span></div></article><article class="panel"><h3>本地 AI</h3><label><span><b>分析模式</b><small>仅允许连接本机端点，原始证据不会发送。</small></span><DesktopSelect v-model="settings.ai_mode" aria-label="分析模式" :options="[{value:'disabled',label:'无 AI（确定性规则）'},{value:'ollama',label:'Ollama 本地模型'}]"/></label><label><span><b>服务地址</b></span><input v-model="settings.ollama_endpoint"></label><label><span><b>模型</b></span><input v-model="settings.ollama_model"></label></article><article class="panel"><h3>高敏感数据</h3><label><span><b>程序 Dump</b><small>可能包含密码、令牌和文档内容；MVP 固定关闭。</small></span><b class="disabled-state">已关闭</b></label></article><button class="primary save" @click="save"><Check/>{{saved?"已保存":"保存设置"}}</button></section>
  </main>
</div>

<div v-if="errorMessage" class="toast"><TriangleAlert/><span>{{errorMessage}}</span><button class="icon" @click="errorMessage=''"><X/></button></div>

<ConfirmDialog id="delete-confirmation" :open="!!confirmation" :busy="confirmationBusy" :title="confirmation?.type==='all'?'删除所有本地数据？':'删除这条事故记录？'" :description="confirmation?.type==='all'?'循环日志、全部事故包和诊断索引将被永久删除；应用设置会保留。此操作无法撤销。':'该事故及其全部证据、分析报告和原始文件将被永久删除。此操作无法撤销。'" :confirm-label="confirmation?.type==='all'?'删除全部数据':'永久删除'" @cancel="confirmation=null" @confirm="confirmRemoval"/>

<div v-if="modal" class="backdrop" @click.self="modal=false"><form class="modal" @submit.prevent="create"><header><div><Zap/><span><h2>标记刚才的问题</h2><p>触发时刻已记录，补充信息即可保存现场。</p></span></div><button type="button" class="icon" @click="modal=false"><X/></button></header><fieldset><legend>发生了什么？</legend><div class="symptoms"><button v-for="s in symptoms" type="button" :class="{active:draft.symptom===s.value}" @click="draft.symptom=s.value"><component :is="s.icon"/>{{s.label}}</button></div></fieldset><div class="form-row"><label>严重程度<DesktopSelect v-model="draft.severity" aria-label="严重程度" :options="[{value:'low',label:'轻微'},{value:'medium',label:'中等'},{value:'high',label:'严重'},{value:'critical',label:'系统不可用'}]"/></label><label>持续多久<DesktopSelect v-model="draft.duration_seconds" aria-label="持续多久" :options="[{value:5,label:'少于 10 秒'},{value:30,label:'约 30 秒'},{value:120,label:'1–2 分钟'}]"/></label></div><label>补充描述（可选）<textarea v-model="draft.description" maxlength="1000" placeholder="例如：切换窗口时整个系统冻结…"></textarea></label><footer><span><ShieldCheck/>数据仅保存在本机</span><button class="primary" :disabled="busy"><Activity/>保存事故现场</button></footer></form></div>
</template>
